function formatDate(value: string | null): string {
  if (!value) {
    return 'No registrado';
  }

  return new Intl.DateTimeFormat('es-EC', {
    dateStyle: 'medium',
    timeStyle: 'short',
  }).format(new Date(value));
}

function invitationStateTone(status: string): string {
  switch (status.toLowerCase()) {
    case 'pending':
      return styles.pending;
    case 'accepted':
      return styles.accepted;
    case 'expired':
      return styles.expired;
    case 'cancelled':
      return styles.cancelled;
    default:
      return '';
  }
}

function flowLabel(flow: AuthenticatedSessionResponse['sessionState']['recommendedFlow']): string {
  switch (flow) {
    case 'workspace':
      return 'Entrar al workspace';
    case 'select-tenancy':
      return 'Elegir tenant';
    case 'accept-invitation':
      return 'Revisar invitacion';
    case 'empty':
      return 'Comenzar onboarding';
    default:
      return flow;
  }
}

function formatMoney(priceInCents: number, currency: string): string {
  return new Intl.NumberFormat('es-EC', {
    style: 'currency',
    currency,
    maximumFractionDigits: 2,
  }).format(priceInCents / 100);
}

function downloadTextArtifact(
  content: string,
  fileName: string,
  contentType: string,
): void {
  const blob = new Blob([content], { type: contentType });
  const url = window.URL.createObjectURL(blob);
  const anchor = window.document.createElement('a');

  anchor.href = url;
  anchor.download = fileName;
  window.document.body.appendChild(anchor);
  anchor.click();
  anchor.remove();
  window.URL.revokeObjectURL(url);
}

function formatInvoiceStatus(status: string): string {
  switch (status.toLowerCase()) {
    case 'draft':
      return 'Borrador';
    case 'issued':
      return 'Emitida';
    case 'partially_paid':
      return 'Parcialmente pagada';
    case 'paid':
      return 'Pagada';
    case 'void':
      return 'Anulada';
    default:
      return status;
  }
}

function formatPaymentStatus(status: string): string {
  switch (status.toLowerCase()) {
    case 'posted':
      return 'Aplicado';
    case 'reversed':
      return 'Revertido';
    default:
      return status;
  }
}

function formatElectronicStatus(status: string | null): string {
  switch (status) {
    case 'pending_submission':
      return 'Pendiente de envio';
    case 'submitted':
      return 'Enviado al SRI';
    case 'authorized':
      return 'Autorizada';
    case 'rejected':
      return 'Rechazada';
    default:
      return 'Sin estado electronico';
  }
}

function formatBuyerIdentificationType(value: string | null): string {
  switch (value) {
    case '04':
      return 'RUC';
    case '05':
      return 'Cedula';
    case '06':
      return 'Pasaporte';
    case '07':
      return 'Consumidor final';
    case '08':
      return 'Exterior';
    default:
      return value ?? 'No configurado';
  }
}

function formatElectronicDocumentLabel(value: string | null): string {
  switch (value) {
    case '04':
      return 'Nota de credito';
    case '05':
      return 'Nota de debito';
    case '06':
      return 'Guia de remision';
    case '07':
      return 'Comprobante de retencion';
    case '01':
    case null:
      return 'Factura';
    default:
      return `Documento ${value}`;
  }
}

function formatPercentage(value: number): string {
  return new Intl.NumberFormat('es-EC', {
    minimumFractionDigits: value % 1 === 0 ? 0 : 2,
    maximumFractionDigits: 2,
  }).format(value);
}

function formatReportMonth(value: string): string {
  const [year, month] = value.split('-');

  if (!year || !month) {
    return value;
  }

  return new Intl.DateTimeFormat('es-EC', {
    month: 'long',
    year: 'numeric',
  }).format(new Date(Number(year), Number(month) - 1, 1));
}

function formatRate(value: number): string {
  return new Intl.NumberFormat('es-EC', {
    style: 'percent',
    minimumFractionDigits: 1,
    maximumFractionDigits: 1,
  }).format(value);
}

function humanizeKey(value: string | null): string {
  if (!value) {
    return 'No definido';
  }

  return value.split('_').join(' ');
}

function resolveNumericYear(value: string): number {
  const parsed = Number.parseInt(value, 10);

  return Number.isFinite(parsed) ? parsed : new Date().getUTCFullYear();
}

type AiAgentWorkspaceSupportBundle = {
  approvalPolicies: AiApprovalPolicyResponse[];
  approvalRequests: AiApprovalRequestResponse[];
  toolAccess: AiAgentToolAccessResponse[];
  suggestionEnvelope: AiSuggestionEnvelopeResponse | null;
  suggestionRuns: AiSuggestionRunResponse[];
};

type AiAgentWorkspaceSupportStateHandler = {
  approvalStatusFilter: AiApprovalRequestStatusFilter;
  applyBundle: (bundle: AiAgentWorkspaceSupportBundle) => void;
  clearBundle: () => void;
  applyApprovalQueue: (approvalRequests: AiApprovalRequestResponse[]) => void;
  setSuggestionRunDetail: (detail: AiSuggestionRunDetailResponse | null) => void;
  syncPrepared?: (suggestionRun: AiSuggestionRunResponse) => void;
  syncPending?: (approvalRequest: AiApprovalRequestResponse) => void;
  syncReviewed?: (approvalRequest: AiApprovalRequestResponse) => void;
};

type StandardAiAgentWorkspaceSupportStateHandlerInput = {
  approvalStatusFilter: AiApprovalRequestStatusFilter;
  setApprovalPolicies: (approvalPolicies: AiApprovalPolicyResponse[]) => void;
  setApprovalRequests: Dispatch<
    SetStateAction<AiApprovalRequestResponse[]>
  >;
  setToolAccess: (toolAccess: AiAgentToolAccessResponse[]) => void;
  setSuggestionEnvelope: (
    envelope: AiSuggestionEnvelopeResponse | null,
  ) => void;
  setSuggestionRuns: Dispatch<SetStateAction<AiSuggestionRunResponse[]>>;
  setSuggestionRunDetail: Dispatch<
    SetStateAction<AiSuggestionRunDetailResponse | null>
  >;
};

type AiDedicatedSuggestionRunActionHandlers = {
  prepare?: () => Promise<void>;
  requestApproval?: (suggestionRunId: string) => Promise<void>;
  reviewApproval?: (
    requestId: string,
    status: 'approved' | 'rejected',
  ) => Promise<void>;
  openDetail?: (suggestionRunId: string) => Promise<void>;
};

function matchesAiApprovalRequestStatusFilter(
  approvalRequest: AiApprovalRequestResponse,
  filter: AiApprovalRequestStatusFilter,
): boolean {
  return filter === 'all' || approvalRequest.status === filter;
}

function bumpSuggestionRunApprovalToPending(
  runs: AiSuggestionRunResponse[],
  approvalRequest: AiApprovalRequestResponse,
): AiSuggestionRunResponse[] {
  return runs.map((entry) =>
    entry.id === approvalRequest.suggestionRunId
      ? {
          ...entry,
          approvalSummary: {
            status: 'pending',
            totalRequests: entry.approvalSummary.totalRequests + 1,
            latestRequestId: approvalRequest.id,
            latestPolicyKey: approvalRequest.policyKey,
            latestRequestedAt: approvalRequest.createdAt,
            latestReviewedAt: approvalRequest.reviewedAt,
          },
        }
      : entry,
  );
}

function applyReviewedApprovalToSuggestionRuns(
  runs: AiSuggestionRunResponse[],
  approvalRequest: AiApprovalRequestResponse,
): AiSuggestionRunResponse[] {
  return runs.map((entry) =>
    entry.id === approvalRequest.suggestionRunId
      ? {
          ...entry,
          approvalSummary: {
            ...entry.approvalSummary,
            status: approvalRequest.status,
            latestRequestId:
              entry.approvalSummary.latestRequestId ?? approvalRequest.id,
            latestPolicyKey:
              entry.approvalSummary.latestPolicyKey ?? approvalRequest.policyKey,
            latestRequestedAt:
              entry.approvalSummary.latestRequestedAt ?? approvalRequest.createdAt,
            latestReviewedAt: approvalRequest.reviewedAt,
          },
        }
      : entry,
  );
}

function prependOrReplaceApprovalRequest(
  approvalRequests: AiApprovalRequestResponse[],
  nextApprovalRequest: AiApprovalRequestResponse,
): AiApprovalRequestResponse[] {
  return [
    nextApprovalRequest,
    ...approvalRequests.filter((entry) => entry.id !== nextApprovalRequest.id),
  ];
}

function bumpSuggestionRunDetailApprovalToPending(
  detail: AiSuggestionRunDetailResponse | null,
  approvalRequest: AiApprovalRequestResponse,
): AiSuggestionRunDetailResponse | null {
  return detail && detail.id === approvalRequest.suggestionRunId
    ? {
        ...detail,
        approvalSummary: {
          status: 'pending',
          totalRequests: detail.approvalSummary.totalRequests + 1,
          latestRequestId: approvalRequest.id,
          latestPolicyKey: approvalRequest.policyKey,
          latestRequestedAt: approvalRequest.createdAt,
          latestReviewedAt: approvalRequest.reviewedAt,
        },
        approvalRequests: prependOrReplaceApprovalRequest(
          detail.approvalRequests,
          approvalRequest,
        ),
      }
    : detail;
}

function applyReviewedApprovalToSuggestionRunDetail(
  detail: AiSuggestionRunDetailResponse | null,
  approvalRequest: AiApprovalRequestResponse,
): AiSuggestionRunDetailResponse | null {
  return detail && detail.id === approvalRequest.suggestionRunId
    ? {
        ...detail,
        approvalSummary: {
          ...detail.approvalSummary,
          status: approvalRequest.status,
          latestReviewedAt: approvalRequest.reviewedAt,
        },
        approvalRequests: prependOrReplaceApprovalRequest(
          detail.approvalRequests,
          approvalRequest,
        ),
      }
    : detail;
}

function syncApprovalRequestsWithFilter(
  approvalRequests: AiApprovalRequestResponse[],
  nextApprovalRequest: AiApprovalRequestResponse,
  filter: AiApprovalRequestStatusFilter,
): AiApprovalRequestResponse[] {
  if (!matchesAiApprovalRequestStatusFilter(nextApprovalRequest, filter)) {
    return approvalRequests.filter((entry) => entry.id !== nextApprovalRequest.id);
  }

  return prependOrReplaceApprovalRequest(approvalRequests, nextApprovalRequest);
}

function prependOrReplaceSuggestionRun(
  runs: AiSuggestionRunResponse[],
  nextRun: AiSuggestionRunResponse,
): AiSuggestionRunResponse[] {
  return [nextRun, ...runs.filter((entry) => entry.id !== nextRun.id)];
}

